final:
module RefModule(
    input [15:0] in,
    input [1:0] ctrl,
    output [15:0] out
);reg [15:0] final_sig;

always @*
begin
    case (ctrl)
        2'b00: final_sig = in;
        2'b01: final_sig = ~in;
        2'b10: final_sig = {in[13:0], 2'b00};
        2'b11: final_sig = {2'b00, in[15:2]};
    endcase
end

assign out = final_sig;

endmodule
